<?php require_once 'mailer.php'; $u=require_login('librarian'); verify_csrf(); if($_SERVER['REQUEST_METHOD']==='POST'){ $bid=(int)$_POST['booking_id']; $action=$_POST['action']??''; $reason=trim($_POST['reason']??''); $q=pdo()->prepare('SELECT b.*,u.id uid,u.email,u.name FROM bookings b JOIN users u ON u.id=b.student_id WHERE b.id=?'); $q->execute([$bid]); $b=$q->fetch(); if($b){ if($action==='accept'&&!active_overlap_exists((int)$b['table_id'])){ $start=date('Y-m-d'); $exp=date('Y-m-d',strtotime('+'.(int)$b['duration_days'].' days')); pdo()->prepare('UPDATE bookings SET status="accepted",start_date=?,expiry_date=?,reviewed_by=? WHERE id=?')->execute([$start,$exp,$u['id'],$bid]); pdo()->prepare('UPDATE payments SET status="verified" WHERE booking_id=?')->execute([$bid]); $b['start_date']=$start;$b['expiry_date']=$exp; email_booking_accepted(['id'=>$b['uid'],'email'=>$b['email']],$b); flash('Booking accepted.'); } elseif($action==='reject'){ pdo()->prepare('UPDATE bookings SET status="rejected",rejection_reason=?,reviewed_by=? WHERE id=?')->execute([$reason,$u['id'],$bid]); pdo()->prepare('UPDATE payments SET status="rejected" WHERE booking_id=?')->execute([$bid]); email_booking_rejected(['id'=>$b['uid'],'email'=>$b['email']],$b,$reason); flash('Booking rejected.'); } else flash('Cannot accept because this table is already active.','err'); }} $pending=pdo()->query('SELECT b.*,u.name,u.email,t.table_code,p.transaction_id FROM bookings b JOIN users u ON u.id=b.student_id JOIN library_tables t ON t.id=b.table_id JOIN payments p ON p.booking_id=b.id WHERE b.status="pending" ORDER BY b.created_at')->fetchAll(); $confirmed=pdo()->query('SELECT b.*,u.name,t.table_code FROM bookings b JOIN users u ON u.id=b.student_id JOIN library_tables t ON t.id=b.table_id WHERE b.status="accepted" ORDER BY b.expiry_date DESC')->fetchAll(); app_header('Librarian Dashboard'); ?><section class="card wide"><h1>Pending Bookings</h1><table><tr><th>Student</th><th>Table</th><th>Amount</th><th>Transaction</th><th>Action</th></tr><?php foreach($pending as $p): ?><tr><td><?=e($p['name'])?><br><?=e($p['email'])?></td><td><?=e($p['table_code'])?></td><td>₹<?=e($p['amount'])?></td><td><?=e($p['transaction_id'])?></td><td><form method="post" class="inline"><?=csrf_field()?><input type="hidden" name="booking_id" value="<?=e($p['id'])?>"><input name="reason" placeholder="Rejection reason"><button class="btn small" name="action" value="accept">Accept</button><button class="btn small danger" name="action" value="reject">Reject</button></form></td></tr><?php endforeach; ?></table></section><section class="card wide"><h2>Confirmed Bookings</h2><?php foreach($confirmed as $c): ?><p><?=e($c['table_code'])?> — <?=e($c['name'])?> until <?=e($c['expiry_date'])?></p><?php endforeach; ?></section><?php app_footer(); ?>
